/**
 * Saves data to Trello chunk by chunk
 * @param scope
 * @param permission
 * @param chunkSize
 * @param key
 * @param data
 * @returns {Promise<void>}
 */
const saveData = async ({scope = 'board', permission = 'shared', chunkSize = 20, key, data}) => {
    let i = 0;
    let slice = [];
    do {
        slice = data.slice(i, i + chunkSize);
        await window.TrelloPowerUp.iframe().set(scope, permission, `${key + i.toString()}`, slice);
        i += chunkSize;
    } while(slice.length === chunkSize);
}

